-- Descrição:
-- Inclui novas classificações tributárias na tabela CLASSIFICACAO_TRIBUTARIA e popula as tabelas relacionadas.
-----------------------------------------------------------------------------------------------

UPDATE CLASSIFICACAO_TRIBUTARIA SET CLTR_IN_APROPRIACAO_CREDITOS_ADQUIRENTES_CBS=0, CLTR_IN_APROPRIACAO_CREDITOS_ADQUIRENTES_IBS=0, CLTR_IN_CREDITO_PRESUMIDO_FORNECEDOR=0, CLTR_IN_CREDITO_PRESUMIDO_ADQUIRENTE=0 WHERE CLTR_ID=69;
UPDATE TRATAMENTO_TRIBUTARIO SET TRTR_DESCRICAO='Tributação em documento específico', TRTR_EXPRESSAO_ALIQUOTA='0' WHERE TRTR_ID=32;
