INSERT INTO FUNDAMENTACAO_CLASSIFICACAO(FDCL_ID,FDCL_CLTR_ID,FDCL_FDLG_ID,FDCL_INICIO_VIGENCIA,FDCL_FIM_VIGENCIA) VALUES(184,184,184,'2026-01-01',NULL);
INSERT INTO FUNDAMENTACAO_LEGAL(FDLG_ID,FDLG_TEXTO,FDLG_TEXTO_CURTO,FDLG_REFERENCIA_NORMATIVA,FDLG_INICIO_VIGENCIA,FDLG_FIM_VIGENCIA) VALUES(176,'Art. 146.\n§ 1º São também reduzidas a zero as alíquotas do IBS e da CBS sobre o fornecimento de medicamentos registrados na Anvisa quando:\nIII – classificados como soros ou vacinas, conforme regulamentação sanitária específica','Art. 146, § 1º, III','LIVRO I \n\nDO IMPOSTO SOBRE BENS E SERVIÇOS (IBS) E DA CONTRIBUIÇÃO SOCIAL SOBRE BENS E SERVIÇOS (CBS) \n\nTÍTULO IV\n\nDOS REGIMES DIFERENCIADOS DO IBS E DA CBS\n\nCAPÍTULO IV\n\nDA REDUÇÃO A ZERO DAS ALÍQUOTAS DO IBS E DA CBS\n\nSeção II\n\nDos Dispositivos Médicos','2026-01-01',NULL);
INSERT INTO FUNDAMENTACAO_LEGAL(FDLG_ID,FDLG_TEXTO,FDLG_TEXTO_CURTO,FDLG_REFERENCIA_NORMATIVA,FDLG_INICIO_VIGENCIA,FDLG_FIM_VIGENCIA) VALUES(177,'Art. 157. Fica isento do IBS e da CBS o fornecimento de serviços de transporte público coletivo de passageiros rodoviário e metroviário de caráter urbano, semiurbano e metropolitano, sob regime de autorização, permissão ou concessão pública.','Art. 157','LIVRO I \n\nDO IMPOSTO SOBRE BENS E SERVIÇOS (IBS) E DA CONTRIBUIÇÃO SOCIAL SOBRE BENS E SERVIÇOS (CBS) \n\nTÍTULO I \n\nDAS NORMAS GERAIS DO IBS E DA CBS \n\nCAPÍTULO II\n\nDO IBS E DA CBS SOBRE OPERAÇÕES COM BENS E SERVIÇOS\n\nSeção V\n\nDa Base de Cálculo','2026-01-01',NULL);
INSERT INTO FUNDAMENTACAO_LEGAL(FDLG_ID,FDLG_TEXTO,FDLG_TEXTO_CURTO,FDLG_REFERENCIA_NORMATIVA,FDLG_INICIO_VIGENCIA,FDLG_FIM_VIGENCIA) VALUES(178,'Art. 12.\n§ 2º Não integram a base de cálculo do IBS e da CBS:\nV - o montante incidente na operação dos tributos a que se referem o inciso II do caput do art. 155, o inciso III do caput do art. 156 e a alínea “b” do inciso I e o inciso IV do caput do art. 195 da Constituição Federal, e da Contribuição para os Programas de Integração Social e de Formação do Patrimônio do Servidor Público (Contribuição para o PIS/Pasep) a que se refere o art. 239 da Constituição Federal, de 1º de janeiro de 2026 a 31 de dezembro de 2032;','Art. 12, §2º V','LIVRO I\n\nDO IMPOSTO SOBRE BENS E SERVIÇOS (IBS) E DA CONTRIBUIÇÃO SOCIAL SOBRE BENS E SERVIÇOS (CBS)\n\nTÍTULO IV\n\nDOS REGIMES DIFERENCIADOS DO IBS E DA CBS\n\nCAPÍTULO V\n\nDO TRANSPORTE PÚBLICO COLETIVO DE PASSAGEIROS RODOVIÁRIO E METROVIÁRIO DE CARÁTER URBANO, SEMIURBANO E METROPOLITANO','2026-01-01',NULL);
INSERT INTO FUNDAMENTACAO_LEGAL(FDLG_ID,FDLG_TEXTO,FDLG_TEXTO_CURTO,FDLG_REFERENCIA_NORMATIVA,FDLG_INICIO_VIGENCIA,FDLG_FIM_VIGENCIA) VALUES(179,'Art. 26.\n§ 5º-A. Para fins do disposto no inciso V do caput deste artigo, não são contribuintes do IBS e da CBS:\nI – os Fundos de Investimento Imobiliário (FII) e os Fundos de Investimento nas Cadeias Produtivas do Agronegócio (Fiagro), de que trata a Lei nº 8.668, de 25 de junho de 1993, que realizem operações com bens imóveis, inclusive operações com direitos reais sobre bens imóveis, e que, cumulativamente:\n(...)\nII – os FII e os Fiagro que realizem operações com bens imóveis, inclusive operações com direitos reais sobre bens imóveis, e que não atendam às condições estabelecidas no inciso I deste parágrafo, cujas cotas sejam detidas, direta ou indiretamente, em mais de 95% (noventa e cinco por cento), por:','Art. 26, § 5º-A, I e II','LIVRO I\n\nDO IMPOSTO SOBRE BENS E SERVIÇOS (IBS) E DA CONTRIBUIÇÃO SOCIAL SOBRE BENS E SERVIÇOS (CBS)\n\nTÍTULO IV\n\nDOS REGIMES DIFERENCIADOS DO IBS E DA CBS\n\nCAPÍTULO V\n\nDO TRANSPORTE PÚBLICO COLETIVO DE PASSAGEIROS RODOVIÁRIO E METROVIÁRIO DE CARÁTER URBANO, SEMIURBANO E METROPOLITANO','2026-01-01',NULL);
INSERT INTO FUNDAMENTACAO_LEGAL(FDLG_ID,FDLG_TEXTO,FDLG_TEXTO_CURTO,FDLG_REFERENCIA_NORMATIVA,FDLG_INICIO_VIGENCIA,FDLG_FIM_VIGENCIA) VALUES(180,'Art. 26.\n§ 5º-A. Para fins do disposto no inciso V do caput deste artigo, não são contribuintes do IBS e da CBS:\nIII – os demais fundos de investimento cujo patrimônio seja constituído exclusivamente por aplicações em participações societárias, certificados, direitos, títulos, valores mobiliários e demais ativos financeiros permitidos pela Comissão de Valores Mobiliários, observado o disposto no § 6º-A e no § 8º-A deste artigo.','Art. 26, § 5º-A, III','LIVRO I\n\nDO IMPOSTO SOBRE BENS E SERVIÇOS (IBS) E DA CONTRIBUIÇÃO SOCIAL SOBRE BENS E SERVIÇOS (CBS)\n\nTÍTULO IV\n\nDOS REGIMES DIFERENCIADOS DO IBS E DA CBS\n\nCAPÍTULO V\n\nDO TRANSPORTE PÚBLICO COLETIVO DE PASSAGEIROS RODOVIÁRIO E METROVIÁRIO DE CARÁTER URBANO, SEMIURBANO E METROPOLITANO','2026-01-01',NULL);
INSERT INTO FUNDAMENTACAO_LEGAL(FDLG_ID,FDLG_TEXTO,FDLG_TEXTO_CURTO,FDLG_REFERENCIA_NORMATIVA,FDLG_INICIO_VIGENCIA,FDLG_FIM_VIGENCIA) VALUES(181,'Art. 26. Não são contribuintes do IBS e da CBS, ressalvado o disposto no inciso II do § 1º do art. 156-A da Constituição Federal:\nIV - nanoempreendedor, assim entendido a pessoa física que tenha auferido receita bruta inferior a 50% (cinquenta por cento) do limite estabelecido para adesão ao regime do MEI previsto no § 1º do art. 18-A observado ainda o disposto nos §§ 4º e 4º-B do referido artigo da Lei Complementar nº 123, de 14 de dezembro de 2006, e não tenha aderido a esse regime','Art. 26, IV','LIVRO I\n\nDO IMPOSTO SOBRE BENS E SERVIÇOS (IBS) E DA CONTRIBUIÇÃO SOCIAL SOBRE BENS E SERVIÇOS (CBS)\n\nTÍTULO IV\n\nDOS REGIMES DIFERENCIADOS DO IBS E DA CBS\n\nCAPÍTULO V\n\nDO TRANSPORTE PÚBLICO COLETIVO DE PASSAGEIROS RODOVIÁRIO E METROVIÁRIO DE CARÁTER URBANO, SEMIURBANO E METROPOLITANO','2026-01-01',NULL);
INSERT INTO FUNDAMENTACAO_LEGAL(FDLG_ID,FDLG_TEXTO,FDLG_TEXTO_CURTO,FDLG_REFERENCIA_NORMATIVA,FDLG_INICIO_VIGENCIA,FDLG_FIM_VIGENCIA) VALUES(182,'Art. 106.\n§ 7º Os benefícios fiscais do regime especial de que trata este artigo aplicam-se também aos beneficiários do Regime Especial de Incentivos para a Produção de Hidrogênio de Baixa Emissão de Carbono (Rehidro), instituído pela Lei nº 14.948, de 2 de agosto de 2024, observada a disciplina estabelecida na legislação específica','Art. 106, § 7º','LIVRO I \n\nDO IMPOSTO SOBRE BENS E SERVIÇOS (IBS) E DA CONTRIBUIÇÃO SOCIAL SOBRE BENS E SERVIÇOS (CBS) \n\nTÍTULO IV\n\nDOS REGIMES DIFERENCIADOS DO IBS E DA CBS\n\nCAPÍTULO III\n\nDA REDUÇÃO EM SESSENTA POR CENTO DAS ALÍQUOTAS DO IBS E DA CBS\n\nSeção X\n\nDos Insumos Agropecuários e Aquícolas','2026-01-01',NULL);
INSERT INTO FUNDAMENTACAO_LEGAL(FDLG_ID,FDLG_TEXTO,FDLG_TEXTO_CURTO,FDLG_REFERENCIA_NORMATIVA,FDLG_INICIO_VIGENCIA,FDLG_FIM_VIGENCIA) VALUES(183,'Art. 172.\n§ 2º Ato conjunto da RFB e do CGIBS preverá hipóteses de suspensão do IBS e da CBS incidentes nas operações com hidrocarbonetos líquidos derivados de petróleo não combustíveis ou de gás natural, inclusive nafta, desde que:\nI – os adquirentes sejam centrais petroquímicas devidamente autorizadas pela ANP;\nII – sejam utilizados como insumo pela indústria petroquímica; e\nIII – obedeçam a critérios e condições estabelecidos no referido ato conjunto.','Art. 172, § 2º','LIVRO I \n\nDO IMPOSTO SOBRE BENS E SERVIÇOS (IBS) E DA CONTRIBUIÇÃO SOCIAL SOBRE BENS E SERVIÇOS (CBS) \n\nTÍTULO IV\n\nDOS REGIMES DIFERENCIADOS DO IBS E DA CBS\n\nCAPÍTULO III\n\nDA REDUÇÃO EM SESSENTA POR CENTO DAS ALÍQUOTAS DO IBS E DA CBS\n\nSeção X\n\nDos Insumos Agropecuários e Aquícolas','2026-01-01',NULL);
INSERT INTO FUNDAMENTACAO_LEGAL(FDLG_ID,FDLG_TEXTO,FDLG_TEXTO_CURTO,FDLG_REFERENCIA_NORMATIVA,FDLG_INICIO_VIGENCIA,FDLG_FIM_VIGENCIA) VALUES(184,'Art. 60. O sujeito passivo do IBS e da CBS, ao realizar operações com bens ou com serviços, inclusive exportações, e importações, deverá emitir documento fiscal eletrônico.\n\n§ 1º As informações prestadas pelo sujeito passivo nos termos deste artigo possuem caráter declaratório e constituem confissão do valor devido de IBS e de CBS consignados no documento fiscal.\n§ 2º A obrigação de emissão de documentos fiscais eletrônicos aplica-se inclusive:\nIII - a outras hipóteses previstas no regulamento.','LC 214','LIVRO I \n\nDO IMPOSTO SOBRE BENS E SERVIÇOS (IBS) E DA CONTRIBUIÇÃO SOCIAL SOBRE BENS E SERVIÇOS (CBS) \n\nTÍTULO V\n\nDOS REGIMES ESPECÍFICOS DO IBS E DA CBS\n\nCAPÍTULO III\n\nDOS PLANOS DE ASSISTÊNCIA À SAÚDE','2026-01-01',NULL);
